module RefModule(
    input       d     ,
    input       clk   ,
    input       reset ,

    output reg  q
);

   // D Flip-Flop with asynchronous reset
     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
       if (reset) begin
           q <= 1'b0;
       end else begin
           q <= d;
       end
   end

endmodule
